var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"큭…","JPN":"ぐっ…","ENG":"Kgh...","TWN":"咳……"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"힐데!","JPN":"ヒルデ！","ENG":"Hilde!","TWN":"希爾德！"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"내가 놈의 발을 묶겠다! 먼저 우물로 가!","JPN":"私がやつを引き留める！　先に井戸に向かえ！","ENG":"I'll keep it busy! Head to the Well first!","TWN":"我來拖住它！你先去井邊！"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"설마 나 혼자 뛰어들라고? 아직 <color=#ffd34c>동앗줄</color>도 연결 못했는데?!","JPN":"まさか、私1人で飛び込めってこと？　まだ<color=#ffd34c>ロープ</color>も繋げてないよ！？","ENG":"You want me to jump in by myself? But I haven't even connected the <color=#ffd34c>Straw Rope</color> yet!","TWN":"不會是讓我一個人跳下去吧？還沒連接上<color=#ffd34c>繩</color>呢？"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"내가 놈들을 막는 것도 곧 한계다.","JPN":"私がやつらを食い止めるのももう限界だ。","ENG":"I can't hold them much longer.","TWN":"我快擋不住它們了。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"일단 시키는 대로 해! 뒷일은 <color=#ffd34c>그 녀석</color>이 어떻게든 해결할 테니!","JPN":"まずは私の言うとおりにしろ！　後は<color=#ffd34c>あいつ</color>がなんとか解決するはずだ！","ENG":"Just do as you're told! <color=#ffd34c>He</color> will take care of the rest for us!","TWN":"照我說的做！之後的事<color=#ffd34c>他</color>會想辦法解決的！"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"아, 알겠어!","JPN":"わ、わかった！","ENG":"O-okay!","TWN":"知、知道了！"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"SOLDIER_DOLL_NPC_NULL","text":{"KOREA":"타깃 하나가 저쪽으로 빠져나간다!","JPN":"片方のターゲットがあちらに逃げていく！","ENG":"One of the targets is escaping!","TWN":"有一個目標正準備逃走！"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"SOLDIER_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"윽…!","JPN":"うっ……！","ENG":"Ngh...!","TWN":"呃……！"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"SOLDIER_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"에라- 모르겠다. 될 대로 되라지!","JPN":"ああーもう、わかんない。なるようになれ！","ENG":"Errgh! Here goes nothing!","TWN":"啊，不管了。順其自然吧！"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"SOLDIER_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"그 이후로, 혼자 남겨진 타깃은 실험동의 특수 격리소에 수감됐어요.","JPN":"あれ以後、1人残されたターゲットは実験棟の特殊隔離所に収監されていますわ。","ENG":"Since then, the remaining target has been detained in a special quarantine center in the experimentation building.","TWN":"這之後，獨自留下斷後的目標被我們羈押在實驗樓的特殊隔離區。"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"꼬리가 달린 꼬마는 그 <color=#ffd34c>우물</color>이란 차원 터널에 몸을 던진 뒤로 사라졌고요.","JPN":"尻尾のついたチビはあの<color=#ffd34c>井戸</color>という次元トンネルに身を投げて消えました。","ENG":"The kid with the tail disappeared after throwing herself into the dimensional tunnel called the <color=#ffd34c>Well</color>.","TWN":"有尾巴的小傢伙在跳進那個被稱為<color=#ffd34c>井</color>的次元隧道後就消失了。"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"우려했던 건 사실이지만, 막상 그 얘길 직접 들으니 충격적이군.","JPN":"心配していたのは事実だが、そんな話を直接聞くと衝撃的だな。","ENG":"It's true that I was concerned, but I'm shocked to hear that in person.","TWN":"雖然擔心的事情成真了，但親耳聽到還是很震驚啊……"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"우리 직원이 누군가에게 전면전으로 질 거라곤 상상도 못했거든.","JPN":"私の職員が誰かとの全面戦争で負けるとは想像もしていなかった。","ENG":"I've never imagined my employee would lose to someone in a head-on battle.","TWN":"我的員工居然會在正面戰鬥中輸給別人，真是想都沒想到。"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"그런 반응도 납득은 되네요.","JPN":"そんな反応も納得はいきますわ。","ENG":"I understand your reaction.","TWN":"我明白你的反應。"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SERIOUS3"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"그 꼬마, 어지간한 S급 카운터보다 저항이 거세서 잡는데 애를 먹었거든요.","JPN":"あのチビ、そこらのS級カウンターより激しく抵抗して捕まえるのに苦労しましたから。","ENG":"That kid. She was more resistant than most S Grade Counters, which made subduing her quite a challenge.","TWN":"那個小鬼比起一般S級制裁者的抵抗還要激烈，抓住她費了我們不少功夫。"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 왜 나에게 이런 사실을 알려주는 거지?","JPN":"だが、どうして私にこんな事実を教えてくれるんだ？","ENG":"But why are you telling me this?","TWN":"但是，你告訴我們這些沒什麼好處吧？"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 작전의 지휘에 일조했던 간부라면, 우릴 찾아 도움을 줄 입장은 아닌 것 같은데.","JPN":"あの作戦の指揮に参加した幹部なら、私たちを探して力を貸すような立場ではないだろう。","ENG":"I don't believe you're in a position to assist us if you were the officer who was a part of that operation.","TWN":"更何況是參與了那次作戰指揮的幹部，為什麼要找上門來幫忙？"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"저에겐 특별한 능력이 있어요.","JPN":"私には特別な能力があります。","ENG":"I have a special ability.","TWN":"我有一種特殊的能力。"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"그리고 전 당신이 제 조언에 따라 그 여자를 구하는 미래를 봤죠.","JPN":"そして私はあなたが私の助言に従ってあの女を救う未来を見たのです。","ENG":"And I saw a future where you followed my advice and saved her.","TWN":"我有看到你按照我的建議，救了那個小鬼的未來。"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"내가 그녀를 구하는 미래가 자네에겐 무슨 득이 되지?","JPN":"私が彼女を救う未来が、君には何の得になるのだ？","ENG":"What do you gain from a future where I save her?","TWN":"這個未來對你有什麼好處？"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LENORE_UNION_NULL_NOBG","text":{"KOREA":"딱히 득이 되는 건 없답니다.","JPN":"別に得になるようなことはありません。","ENG":"Nothing in particular.","TWN":"沒什麼好處。"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NOBG","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LENORE_UNION_NULL_NOBG","text":{"KOREA":"전 단지 펠릭스, 그 여자 뜻대로 되는 게 마음에 들지 않을 뿐이죠.","JPN":"私はただフェリックス、あの女の思いどおりになるのが気に入らないだけです。","ENG":"I merely dislike that woman, Felix, getting her way.","TWN":"我只是覺得不能讓緋莉克絲那個女的心意如願而已。"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NOBG","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};